// import React from 'react'
class Subscribe {
  constructor(data: Record<string, any>) {
    Object.keys(data).forEach((k) => (this[k] = data[k]))
  }
}

export function createSubscribe(data: Record<string, any>) {
  return new Subscribe(data)
}

export function subscribe<T extends Subscribe>(target: T, callback: Function) {
  Object.keys(target).forEach((k) => subscribeKey(target, k, callback))
}

export function subscribeKey<T extends Subscribe>(target: T, key: string, callback: Function) {
  // const [, rd] = React.useState(1)

  let value = target[key]
  Object.defineProperty(target, key, {
    get() {
      return value
    },
    set(v) {
      if (!Object.is(v, value)) {
        value = v
        callback()
        // rd((o) => ++o)
      }
    },
    enumerable: true,
    configurable: true
  })
}
